import json
import pickle

class UserPreferences:
    def __init__(self):
        self.preferences = {}

    def set_preference(self, key, value):
        self.preferences[key] = value

    def get_preference(self, key):
        return self.preferences.get(key)

def save_preferences(preferences, filename):
    with open(filename, 'wb') as file:
        pickle.dump(preferences, file)

def load_preferences(filename):
    with open(filename, 'rb') as file:
        preferences = pickle.load(file)
    return preferences

# Example usage
if __name__ == "__main__":
    user_prefs = UserPreferences()
    user_prefs.set_preference('theme', 'dark')
    user_prefs.set_preference('notifications', {'email': True, 'sms': False})
    user_prefs.set_preference('favorite_colors', ['blue', 'green'])

    save_preferences(user_prefs.preferences, 'user_preferences.pkl')

    loaded_prefs = load_preferences('user_preferences.pkl')
    print(loaded_prefs)